dashboard.definition:
{
  "title": "Source - Webex API",
  "description": "Cisco Webex REST API — audit API usage, detect unauthorized integrations, track admin actions",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total Webex API Events Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt (sourcetype=\"FAKE:cisco:webex:meetings\" OR sourcetype=\"FAKE:cisco:webex:admin:audit:events\" OR sourcetype=\"FAKE:cisco:webex:security:audit:events\" OR sourcetype=\"FAKE:cisco:webex:meeting:qualities\" OR sourcetype=\"FAKE:cisco:webex:call:detailed_history\") by _time span=1h"
      }
    },
    "ds_admin_actions": {
      "type": "ds.search",
      "name": "Admin Actions",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:cisco:webex:admin:audit:events\" OR sourcetype=\"FAKE:cisco:webex:security:audit:events\") | stats count"
      }
    },
    "ds_api_calls": {
      "type": "ds.search",
      "name": "API Calls",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:cisco:webex:meetings\" OR sourcetype=\"FAKE:cisco:webex:meeting:qualities\" OR sourcetype=\"FAKE:cisco:webex:call:detailed_history\") | stats count"
      }
    },
    "ds_unique_actors": {
      "type": "ds.search",
      "name": "Unique Actors",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:cisco:webex:meetings\" OR sourcetype=\"FAKE:cisco:webex:admin:audit:events\" OR sourcetype=\"FAKE:cisco:webex:security:audit:events\" OR sourcetype=\"FAKE:cisco:webex:meeting:qualities\" OR sourcetype=\"FAKE:cisco:webex:call:detailed_history\") | eval user=coalesce(hostEmail, actorEmail, user) | where isnotnull(user) | stats dc(user) as count"
      }
    },
    "ds_events_over_time": {
      "type": "ds.search",
      "name": "Events Over Time by Sourcetype",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:cisco:webex:meetings\" OR sourcetype=\"FAKE:cisco:webex:admin:audit:events\" OR sourcetype=\"FAKE:cisco:webex:security:audit:events\" OR sourcetype=\"FAKE:cisco:webex:meeting:qualities\" OR sourcetype=\"FAKE:cisco:webex:call:detailed_history\") | eval st=replace(sourcetype,\"FAKE:cisco:webex:\",\"\") | timechart span=1h count by st"
      }
    },
    "ds_by_sourcetype": {
      "type": "ds.search",
      "name": "Events by Type",
      "options": {
        "query": "| tstats count where index=fake_tshrt (sourcetype=\"FAKE:cisco:webex:meetings\" OR sourcetype=\"FAKE:cisco:webex:admin:audit:events\" OR sourcetype=\"FAKE:cisco:webex:security:audit:events\" OR sourcetype=\"FAKE:cisco:webex:meeting:qualities\" OR sourcetype=\"FAKE:cisco:webex:call:detailed_history\") by sourcetype"
      }
    },
    "ds_top_actors": {
      "type": "ds.search",
      "name": "Top Actors",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:cisco:webex:meetings\" OR sourcetype=\"FAKE:cisco:webex:admin:audit:events\" OR sourcetype=\"FAKE:cisco:webex:security:audit:events\" OR sourcetype=\"FAKE:cisco:webex:meeting:qualities\" OR sourcetype=\"FAKE:cisco:webex:call:detailed_history\") | eval user=coalesce(hostEmail, actorEmail, user) | where isnotnull(user) | stats count by user | sort -count | head 15 | rename user as \"Actor\""
      }
    },
    "ds_sample_events": {
      "type": "ds.search",
      "name": "Recent Events",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:cisco:webex:meetings\" OR sourcetype=\"FAKE:cisco:webex:admin:audit:events\" OR sourcetype=\"FAKE:cisco:webex:security:audit:events\" OR sourcetype=\"FAKE:cisco:webex:meeting:qualities\" OR sourcetype=\"FAKE:cisco:webex:call:detailed_history\") | eval display_type=coalesce(type, title, action) | eval display_user=coalesce(hostEmail, actorEmail, user) | table _time sourcetype host display_type display_user | sort -_time | head 30 | rename sourcetype as \"Sourcetype\" display_type as \"Type/Title\" display_user as \"Actor\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — Webex API\n\n**Sourcetypes:** `FAKE:cisco:webex:meetings`, `FAKE:cisco:webex:admin:audit:events`, `FAKE:cisco:webex:security:audit:events`, `FAKE:cisco:webex:meeting:qualities`, `FAKE:cisco:webex:call:detailed_history` | **Coverage:** Webex REST API data | **Format:** JSON\n\n**Why monitor?** Audit API usage patterns to detect unauthorized integrations, track admin configuration changes, and ensure compliance with collaboration security policies.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_events": {
      "type": "splunk.singlevalue",
      "title": "Total Events",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_admin_actions": {
      "type": "splunk.singlevalue",
      "title": "Admin Actions",
      "dataSources": { "primary": "ds_admin_actions" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_api_calls": {
      "type": "splunk.singlevalue",
      "title": "API Calls",
      "dataSources": { "primary": "ds_api_calls" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#53A051",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_actors": {
      "type": "splunk.singlevalue",
      "title": "Unique Actors",
      "dataSources": { "primary": "ds_unique_actors" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_events_over_time": {
      "type": "splunk.area",
      "title": "Events Over Time by Sourcetype",
      "dataSources": { "primary": "ds_events_over_time" },
      "options": {
        "stackMode": "stacked",
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "areaOpacity": 0.7,
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Events / hour",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColors": ["#00D2FF", "#7B56DB", "#53A051", "#F8BE34", "#DC4E41"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_by_sourcetype": {
      "type": "splunk.pie",
      "title": "Events by Type",
      "dataSources": { "primary": "ds_by_sourcetype" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColors": ["#00D2FF", "#7B56DB", "#53A051", "#F8BE34", "#DC4E41"]
      }
    },
    "viz_top_actors": {
      "type": "splunk.bar",
      "title": "Top Actors",
      "dataSources": { "primary": "ds_top_actors" },
      "options": {
        "seriesColors": ["#7B56DB"],
        "legendDisplay": "off",
        "xAxisTitleText": "Events",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_sample_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent Events",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_sample_events": {
      "type": "splunk.table",
      "title": "Recent Events",
      "dataSources": { "primary": "ds_sample_events" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 160 } },
      { "item": "viz_kpi_total_events", "type": "block", "position": { "x": 0, "y": 160, "w": 300, "h": 120 } },
      { "item": "viz_kpi_admin_actions", "type": "block", "position": { "x": 300, "y": 160, "w": 300, "h": 120 } },
      { "item": "viz_kpi_api_calls", "type": "block", "position": { "x": 600, "y": 160, "w": 300, "h": 120 } },
      { "item": "viz_kpi_actors", "type": "block", "position": { "x": 900, "y": 160, "w": 300, "h": 120 } },
      { "item": "viz_events_over_time", "type": "block", "position": { "x": 0, "y": 280, "w": 750, "h": 350 } },
      { "item": "viz_by_sourcetype", "type": "block", "position": { "x": 750, "y": 280, "w": 450, "h": 350 } },
      { "item": "viz_top_actors", "type": "block", "position": { "x": 0, "y": 630, "w": 1200, "h": 300 } },
      { "item": "viz_sample_header", "type": "block", "position": { "x": 0, "y": 930, "w": 1200, "h": 50 } },
      { "item": "viz_sample_events", "type": "block", "position": { "x": 0, "y": 980, "w": 1200, "h": 400 } }
    ]
  }
}
